import{_ as t,o as a,c as e,ag as i}from"./chunks/framework.BZohXCq9.js";const s=JSON.parse('{"title":"[Admin] Kho tính năng: Quản trị Nội dung (Content CMS)","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/03-kho-tinh-nang/quan-tri-noi-dung/admin-features.md","filePath":"99-tham-khao/archive/03-kho-tinh-nang/quan-tri-noi-dung/admin-features.md"}'),l={name:"99-tham-khao/archive/03-kho-tinh-nang/quan-tri-noi-dung/admin-features.md"};function r(h,n,o,u,g,d){return a(),e("div",null,[...n[0]||(n[0]=[i('<h1 id="admin-kho-tinh-nang-quan-tri-noi-dung-content-cms" tabindex="-1">[Admin] Kho tính năng: Quản trị Nội dung (Content CMS) <a class="header-anchor" href="#admin-kho-tinh-nang-quan-tri-noi-dung-content-cms" aria-label="Permalink to &quot;[Admin] Kho tính năng: Quản trị Nội dung (Content CMS)&quot;">​</a></h1><table tabindex="0"><thead><tr><th style="text-align:left;">Phiên bản</th><th style="text-align:left;">Ngày</th><th style="text-align:left;">Sprint</th><th style="text-align:left;">Nội dung thay đổi</th><th style="text-align:left;">Người thực hiện</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>v1.0</strong></td><td style="text-align:left;">26/03/2026</td><td style="text-align:left;"><a href="./../../02-quan-ly-sprint/sprint-2-quan-tri-diem-den/01-yeu-cau-nghiep-vu">Sprint 2</a></td><td style="text-align:left;">Khởi tạo đặc tả nội dung Admin ban đầu</td><td style="text-align:left;">PO</td></tr></tbody></table><hr><p>Hệ thống quản trị nội dung trung tâm cho phép cấu hình toàn bộ dữ liệu nền của Vivu Travel.</p><h2 id="_1-quan-ly-vung-mien-regional-management" tabindex="-1">1. Quản lý Vùng miền (Regional Management) <a class="header-anchor" href="#_1-quan-ly-vung-mien-regional-management" aria-label="Permalink to &quot;1. Quản lý Vùng miền (Regional Management)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: Thêm/Sửa/Xóa danh mục vùng miền (Miền Bắc, Trung, Nam, Cao nguyên...).</li><li><strong>Quy trình</strong>: Định nghĩa mã vùng (Region Code) để dùng cho việc lọc (Filter) tại Client.</li></ul><h2 id="_2-quan-ly-điem-đen-destination-crud" tabindex="-1">2. Quản lý Điểm đến (Destination CRUD) <a class="header-anchor" href="#_2-quan-ly-điem-đen-destination-crud" aria-label="Permalink to &quot;2. Quản lý Điểm đến (Destination CRUD)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: <ul><li>Quản lý metadata (Tên, mô tả, slug).</li><li>Quản lý tọa độ Map (Lat/Long).</li><li>Quản lý Media (Cloudinary multi-upload).</li></ul></li><li><strong>Quy tắc</strong>: Không xóa điểm đến khi có Tour đang Active.</li></ul><h2 id="_3-quan-ly-tour-gia-tour-management" tabindex="-1">3. Quản lý Tour &amp; Giá (Tour Management) <a class="header-anchor" href="#_3-quan-ly-tour-gia-tour-management" aria-label="Permalink to &quot;3. Quản lý Tour &amp; Giá (Tour Management)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: <ul><li>Tạo lịch trình Tour (Day-by-day itineraries).</li><li>Cấu hình bảng giá theo loại khách (Người lớn, Trẻ em).</li><li>Quản lý trạng thái Tour (Active/Inactive/Draft).</li></ul></li></ul><h2 id="_4-quan-ly-hinh-anh-media-center" tabindex="-1">4. Quản lý Hình ảnh (Media Center) <a class="header-anchor" href="#_4-quan-ly-hinh-anh-media-center" aria-label="Permalink to &quot;4. Quản lý Hình ảnh (Media Center)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: Thư viện ảnh tập trung, hỗ trợ gắn tag và tìm kiếm ảnh theo điểm đến.</li></ul>',12)])])}const c=t(l,[["render",r]]);export{s as __pageData,c as default};
